function getIngCategory(name) {
  const low = name.toLowerCase();
  // Sort by key length descending so longer/more specific keys match first
  const entries = Object.entries(INGREDIENT_CATEGORIES).sort((a,b) => b[0].length - a[0].length);
  for (const [key, cat] of entries) {
    if (low.includes(key)) return cat;
  }
  return 'Other';
}


