// ══════════════════════════════════════════════════
// PLAN TAB
// ══════════════════════════════════════════════════
const SLOTS = ['Breakfast','Lunch','Dinner','Meal Prep'];
const DAYS = ['Mon','Tue','Wed','Thu','Fri','Sat','Sun'];

function getWeekStart(offset=0) {
  const now = new Date();
  const day = now.getDay(); // 0=Sun
  const diff = day===0 ? -6 : 1-day; // shift to Monday
  const mon = new Date(now);
  mon.setDate(now.getDate() + diff + offset*7);
  mon.setHours(0,0,0,0);
  return mon;
}

function dayKey(weekStart, dayIdx) {
  const d = new Date(weekStart);
  d.setDate(d.getDate() + dayIdx);
  return d.toISOString().slice(0,10);
}

function changeWeek(delta) {
  currentWeekOffset += delta;
  if (currentWeekOffset === 0) {
    const _t = new Date(); _t.setHours(0,0,0,0);
    const _ws = getWeekStart(0);
    const _d = Math.round((_t - _ws) / 86400000);
    selectedDayIndex = (_d >= 0 && _d < 7) ? _d : 0;
  } else { selectedDayIndex = 0; }
  renderPlanView();
}

function renderPlanView() {
  const ws = getWeekStart(currentWeekOffset);
  const today = new Date(); today.setHours(0,0,0,0);

  // Week label
  const end = new Date(ws); end.setDate(ws.getDate()+6);
  const fmt = d => d.toLocaleDateString('en-US',{month:'short',day:'numeric'});
  document.getElementById('week-label').textContent = `${fmt(ws)} – ${fmt(end)}`;

  // Day strip
  const strip = document.getElementById('day-strip');
  strip.innerHTML = DAYS.map((d,i) => {
    const dt = new Date(ws); dt.setDate(ws.getDate()+i);
    const isToday = dt.getTime()===today.getTime();
    return `<button class="day-pill ${i===selectedDayIndex?'active':''}" data-action="selectDay" data-day-index="${i}">
      <span class="day-pill-name">${d}</span>
      <span class="day-pill-date">${dt.getDate()}${isToday?' ·':''}</span>
    </button>`;
  }).join('');

  renderDayView();
}

function selectDay(idx) {
  selectedDayIndex = idx;
  renderPlanView();
}

function renderDayView() {
  const ws = getWeekStart(currentWeekOffset);
  const dk = dayKey(ws, selectedDayIndex);
  const plan = getPlanData();
  const dayPlan = plan[dk] || {};
  const notes = dayPlan._notes || {};
  const prepItems = getPrepItems();

  const dayEl = document.getElementById('plan-day-view');
  const mealSlots = SLOTS.filter(s => s !== 'Meal Prep').map(slot => {
    const recipes = dayPlan[slot] || [];
    const noteVal = notes[slot] || '';
    const textVal = notes[slot+'_text'] || '';
    const items = recipes.length
      ? recipes.map((rid,ri) => {
          const r = RECIPES.find(x=>x.id===rid);
          return `<div class="slot-recipe-item">
            <span class="slot-recipe-name" data-action="openRecipeFromPlan" data-id="${rid}" title="Tap to view recipe">${r?r.title:rid} <span style="opacity:0.35;font-size:11px">↗</span></span>
            <button class="slot-remove-btn" data-action="removeFromSlot" data-dk="${dk}" data-slot="${slot}" data-ri="${ri}">✕</button>
          </div>`;
        }).join('')
      : '';
    // Lunch quick suggestions
    const lunchSuggestions = slot === 'Lunch' ? `
      <div style="display:flex;gap:6px;margin-bottom:6px;flex-wrap:wrap">
        <button data-action="addQuickText" data-dk="${dk}" data-slot="Lunch" data-text="Leftovers" style="background:var(--offwhite);border:1px solid var(--border);border-radius:16px;padding:4px 12px;font-family:'Jost',sans-serif;font-size:11px;color:var(--text-light);cursor:pointer;white-space:nowrap">🍱 Leftovers</button>
        <button data-action="addQuickText" data-dk="${dk}" data-slot="Lunch" data-text="Charcuterie plate" style="background:var(--offwhite);border:1px solid var(--border);border-radius:16px;padding:4px 12px;font-family:'Jost',sans-serif;font-size:11px;color:var(--text-light);cursor:pointer;white-space:nowrap">🧀 Charcuterie plate</button>
      </div>` : '';
    return `
      <div class="meal-slot">
        <div class="slot-header">
          <span class="slot-title">${slot}</span>
          <button class="slot-add-btn" data-action="openPicker" data-dk="${dk}" data-slot="${slot}">+</button>
        </div>
        <div class="slot-body">
          ${lunchSuggestions}
          ${items || ''}
          <input class="slot-text-input" placeholder="${slot === 'Lunch' ? 'Or type anything…' : 'Type a meal or note…'}"
            value="${textVal.replace(/"/g,'&quot;')}"
            data-slot-text="${dk}|${slot}"
            style="width:100%;border:none;background:none;font-family:'Jost',sans-serif;font-size:16px;color:var(--text);padding:4px 0 6px;outline:none;border-bottom:1px solid var(--border);margin-top:${items?'6px':'0'}">
          <textarea class="slot-note-input" placeholder="Notes…" data-slot-note="${dk}|${slot}">${noteVal}</textarea>
        </div>
      </div>`;
  }).join('');

  // Meal prep section (week-level)
  const totalPrep = prepItems.length;
  const donePrep = prepItems.filter(x=>x.checked).length;
  const pct = totalPrep ? Math.round((donePrep/totalPrep)*100) : 0;

  const progressHTML = totalPrep ? `
    <div class="prep-progress-wrap">
      <div class="prep-progress-bar-bg">
        <div class="prep-progress-bar-fill" style="width:${pct}%"></div>
      </div>
      <div class="prep-progress-label">${donePrep} of ${totalPrep} complete</div>
    </div>` : '';

  dayEl.innerHTML = mealSlots + `
    <div class="prep-section">
      <div class="prep-header">
        <span class="prep-title">Meal Prep & Staples — This Week</span>
      </div>
      ${progressHTML}
      <div class="prep-body">
        ${buildPrepOptimizer(prepItems)}
        ${buildPrepByCategory(prepItems) || '<div class="slot-empty" style="padding:6px 0">Add tasks or recipes for your weekly batch cook</div>'}
        <div class="prep-add-row">
          <input class="prep-add-input" id="prep-input" placeholder="e.g. Mill flour, make granola…" onkeydown="if(event.key===\'Enter\')addPrep()">
          <button class="prep-add-go" data-action="addPrep">Add</button>
        </div>
        <button class="prep-recipe-btn" data-action="openPrepRecipePicker">+ Add a Recipe</button>
      </div>
    </div>`;
}

function saveSlotNote(dk, slot, val) {
  const plan = getPlanData();
  if (!plan[dk]) plan[dk] = {};
  if (!plan[dk]._notes) plan[dk]._notes = {};
  plan[dk]._notes[slot] = val;
  savePlanData(plan);
}

function saveSlotText(dk, slot, val) {
  const plan = getPlanData();
  if (!plan[dk]) plan[dk] = {};
  if (!plan[dk]._notes) plan[dk]._notes = {};
  plan[dk]._notes[slot+'_text'] = val;
  savePlanData(plan);
  if (planView === 'week') renderWeekView();
}

function addQuickText(dk, slot, text) {
  const plan = getPlanData();
  if (!plan[dk]) plan[dk] = {};
  if (!plan[dk]._notes) plan[dk]._notes = {};
  const existing = plan[dk]._notes[slot+'_text'] || '';
  plan[dk]._notes[slot+'_text'] = existing ? existing + ', ' + text : text;
  savePlanData(plan);
  renderDayView();
}

function removeFromSlot(dk, slot, idx) {
  const plan = getPlanData();
  if (plan[dk]?.[slot]) {
    plan[dk][slot].splice(idx,1);
    savePlanData(plan);
    renderDayView();
    rebuildShoppingList();
  }
}

function addToSlot(dk, slot, recipeId) {
  const plan = getPlanData();
  if (!plan[dk]) plan[dk] = {};
  if (!plan[dk][slot]) plan[dk][slot] = [];
  plan[dk][slot].push(recipeId);
  savePlanData(plan);
  renderDayView();
  rebuildShoppingList();
}

function addPrep() {
  const input = document.getElementById('prep-input');
  const val = input.value.trim();
  if (!val) return;
  const items = getPrepItems();
  items.push({name:val, checked:false});
  savePrepItems(items);
  input.value = '';
  renderDayView();
}

function addPrepRecipe(id) {
  const r = RECIPES.find(x=>x.id===id);
  if (!r) return;
  const items = getPrepItems();
  items.push({name:r.title, checked:false, recipeId:id});
  savePrepItems(items);
  closePicker();
  renderDayView();
}

function openPrepRecipePicker() {
  pickerTarget = {dk: null, slot: '__prep__'};
  document.getElementById('picker-title').textContent = 'Add to Meal Prep';
  document.getElementById('picker-search').value = '';
  filterPicker();
  document.getElementById('picker-sheet').classList.add('open');
}

// closePrepPicker merged into closePicker

function removePrep(i) {
  const items = getPrepItems();
  items.splice(i,1);
  savePrepItems(items);
  renderDayView();
}

function togglePrep(i) {
  const items = getPrepItems();
  items[i].checked = !items[i].checked;
  savePrepItems(items);
  renderDayView();
  if (planView === 'week') renderWeekView();
}

function savePrepNote(i, val) {
  const items = getPrepItems();
  if (items[i]) { items[i].note = val; savePrepItems(items); }
}

function togglePrepNote(i) {
  const inp = document.getElementById('prep-note-wrap-'+i);
  if (!inp) return;
  const isHidden = inp.style.display === 'none' || inp.style.display === '';
  inp.style.display = isHidden ? 'flex' : 'none';
  if (isHidden) inp.focus();
}

// ── Plan sub-views ──
function switchPlanView(view) {
  document.getElementById('plan-main-view').style.display = view==='main'?'block':'none';
  document.getElementById('plan-shop-view').style.display = view==='shop'?'block':'none';
  if (view==='shop') renderShoppingList();
}

