// TIMER
// ══════════════════════════════════════════════════
// ── Wake lock handle ─────────────────────────────────────────────────────
var _wakeLock = null;
async function _requestWakeLock() {
  try {
    if ('wakeLock' in navigator) {
      _wakeLock = await navigator.wakeLock.request('screen');
    }
  } catch(e) { /* not supported or denied — silent */ }
}
function _releaseWakeLock() {
  try { if (_wakeLock) { _wakeLock.release(); _wakeLock = null; } } catch(e) {}
}
// Re-acquire wake lock if page becomes visible again (e.g. switching tabs)
document.addEventListener('visibilitychange', function() {
  if (_wakeLock !== null && document.visibilityState === 'visible') _requestWakeLock();
});

// Track current timer minutes for the Open Clock button
var _timerMinutes = 0;
var _timerLabel = '';

function startTimer(minutes, btn) {
  if (timerInterval) clearInterval(timerInterval);
  _releaseWakeLock();
  document.querySelectorAll('.timer-btn.running').forEach(b => b.classList.remove('running'));
  timerRemaining = minutes * 60;
  _timerMinutes = minutes;
  // Grab step label from button text for clock button display
  _timerLabel = btn.textContent.replace('⏱','').replace('timer','').trim();
  btn.classList.add('running');
  const toast = document.getElementById('timer-toast');
  const disp = document.getElementById('timer-display');
  const clockBtn = document.getElementById('timer-clock-btn');
  if (clockBtn) clockBtn.title = 'Open Clock — ' + _timerLabel;
  toast.style.display = 'flex';
  // Request wake lock so screen stays on while timer runs
  _requestWakeLock();
  function tick() {
    const m = Math.floor(timerRemaining/60), s = timerRemaining%60;
    disp.textContent = m + ':' + String(s).padStart(2,'0');
    if (timerRemaining <= 0) {
      clearInterval(timerInterval);
      disp.textContent = '✓ Done!';
      btn.classList.remove('running');
      _releaseWakeLock();
      // Haptic feedback: triple pulse
      if (navigator.vibrate) navigator.vibrate([300, 150, 300, 150, 300]);
      // Audio chime using Web Audio API
      try {
        var ctx = new (window.AudioContext || window.webkitAudioContext)();
        [0, 0.4, 0.8].forEach(function(t) {
          var osc = ctx.createOscillator();
          var gain = ctx.createGain();
          osc.connect(gain); gain.connect(ctx.destination);
          osc.frequency.value = 880;
          osc.type = 'sine';
          gain.gain.setValueAtTime(0.4, ctx.currentTime + t);
          gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + t + 0.4);
          osc.start(ctx.currentTime + t);
          osc.stop(ctx.currentTime + t + 0.4);
        });
      } catch(e) {}
      setTimeout(function() {
        toast.style.display = 'none';
        btn.classList.remove('running');
      }, 3000);
    }
    timerRemaining--;
  }
  tick();
  timerInterval = setInterval(tick, 1000);
}
function cancelTimer() {
  if (timerInterval) clearInterval(timerInterval);
  document.getElementById('timer-toast').style.display = 'none';
  document.querySelectorAll('.timer-btn.running').forEach(b => b.classList.remove('running'));
  _releaseWakeLock();
}

function openPhoneClock() {
  var mins = _timerMinutes;
  var label = _timerLabel;
  var timeStr = mins >= 60
    ? Math.floor(mins/60) + 'h ' + (mins%60 ? mins%60 + 'm' : '')
    : mins + ' min';
  // Show a clear overlay with instructions — URL schemes blocked in PWA mode
  var overlay = document.createElement('div');
  overlay.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.85);z-index:9999;display:flex;flex-direction:column;align-items:center;justify-content:center;color:white;font-family:Jost,sans-serif;padding:32px;text-align:center;';
  overlay.innerHTML =
    '<div style="font-size:13px;letter-spacing:1.5px;text-transform:uppercase;opacity:0.6;margin-bottom:16px;">Set a Phone Timer</div>'
    + '<div style="font-size:72px;font-weight:200;line-height:1;margin-bottom:8px;">' + timeStr + '</div>'
    + '<div style="font-size:16px;opacity:0.7;margin-bottom:32px;">' + label + '</div>'
    + '<div style="font-size:14px;line-height:1.7;opacity:0.85;max-width:280px;margin-bottom:36px;">'
    + 'Open your <strong>Clock app</strong> and set a timer for <strong>' + timeStr + '</strong> to get a notification when your phone is locked.'
    + '</div>'
    + '<button data-action="dismissParent" style="background:white;color:#333;border:none;border-radius:24px;padding:12px 32px;font-family:Jost,sans-serif;font-size:15px;font-weight:500;cursor:pointer;">Got it</button>';
  document.body.appendChild(overlay);
}

function exportMealPlan() {
  var PLANNER_URL = './planner.png';
  var plan = getPlanData();
  var weekStart = getWeekStart(currentWeekOffset);

  var CW = 1546, CH = 2000;
  var COL_B = 484, COL_L = 842, COL_D = 1201;
  var CELL_W = 290, CELL_H = 229;
  var ROW_Y = [246, 493, 740, 987, 1234, 1481, 1728];

  function drawAndExport(img) {
    var canvas = document.createElement('canvas');
    canvas.width = CW; canvas.height = CH;
    var ctx = canvas.getContext('2d');
    ctx.drawImage(img, 0, 0, CW, CH);
    ctx.fillStyle = '#3d3830';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';

    function wrapText(text, cx, cy, maxW, maxH) {
      text = (text || '').trim();
      if (!text) return;
      var sizes = [38, 32, 27, 23, 19, 16];
      var chosenFs = 16, chosenLines = [text];
      for (var si = 0; si < sizes.length; si++) {
        var fs = sizes[si];
        ctx.font = '400 ' + fs + 'px Jost, sans-serif';
        var lh = fs * 1.25;
        var words = text.split(' '), ls = [], cur = '';
        for (var wi = 0; wi < words.length; wi++) {
          var t = cur ? cur + ' ' + words[wi] : words[wi];
          if (ctx.measureText(t).width > maxW && cur) { ls.push(cur); cur = words[wi]; }
          else cur = t;
        }
        if (cur) ls.push(cur);
        if (ls.length * lh <= maxH * 0.75) { chosenFs = fs; chosenLines = ls; break; }
      }
      ctx.font = '400 ' + chosenFs + 'px Jost, sans-serif';
      var lh = chosenFs * 1.25;
      var sy = cy - (chosenLines.length * lh) / 2 + lh / 2;
      for (var li = 0; li < chosenLines.length; li++) { ctx.fillText(chosenLines[li], cx, sy); sy += lh; }
    }

    for (var i = 0; i < 7; i++) {
      var date = new Date(weekStart);
      date.setDate(date.getDate() + i);
      var dk = date.toISOString().slice(0, 10);
      var dp = plan[dk] || {}, notes = dp._notes || {};

      function makeSlotText(slot) {
        var ids = (dp[slot] || []).filter(Boolean);
        if (ids.length) {
          var names = ids.map(function(id) {
            var r = RECIPES.find(function(r) { return r.id === id; });
            return r ? r.title : '';
          }).filter(Boolean);
          if (names.length) return names.join(' + ');
        }
        return (notes[slot + '_text'] || '').trim();
      }

      wrapText(makeSlotText('Breakfast'), COL_B, ROW_Y[i], CELL_W, CELL_H);
      wrapText(makeSlotText('Lunch'),     COL_L, ROW_Y[i], CELL_W, CELL_H);
      wrapText(makeSlotText('Dinner'),    COL_D, ROW_Y[i], CELL_W, CELL_H);
    }

    var link = document.createElement('a');
    link.download = 'my-meal-plan.png';
    link.href = canvas.toDataURL('image/png', 0.95);
    document.body.appendChild(link); link.click(); document.body.removeChild(link);
  }

  var btn = document.querySelector('[data-action="exportMealPlan"]');
  if (btn) { btn.innerHTML = '\u23f3'; btn.disabled = true; }

  var img = new Image();
  img.crossOrigin = 'anonymous';
  img.onload = function() {
    try { drawAndExport(img); } catch(e) { alert('Export failed: ' + e.message); }
    if (btn) { btn.innerHTML = '📤'; btn.disabled = false; }
  };
  img.onerror = function() {
    if (btn) { btn.innerHTML = '📤'; btn.disabled = false; }
    alert('Could not load planner template. Check your connection.');
  };
  setTimeout(function() {
    if (btn && btn.disabled) { btn.innerHTML = '📤'; btn.disabled = false; }
  }, 15000);
  img.src = PLANNER_URL + '?v=' + Date.now();
}

