  function dtFilterIngredients(val){
    if(!val||val.trim().length<2){document.getElementById('dt-result').innerHTML='';return;}
    var terms=val.toLowerCase().split(/[,\s]+/).filter(function(t){return t.length>1;});
    if(!terms.length)return;
    var matches=RECIPES.filter(function(r){
      var h=(r.title+' '+(r.ingredients||[]).join(' ')).toLowerCase();
      return terms.some(function(t){return h.indexOf(t)!==-1;});
    }).slice(0,5);
    var res=document.getElementById('dt-result');
    if(!matches.length){res.innerHTML='<span style="opacity:.5;font-size:12px">No matches — try different ingredients</span>';return;}
    res.innerHTML='<div style="font-size:10px;letter-spacing:1px;text-transform:uppercase;opacity:.45;margin-bottom:6px">Tap to view</div>'+
      matches.map(function(r){
        return '<div class="dt-recipe-chip" onclick=\"switchTab(\'recipes\');setTimeout(function(){openRecipe(\''+r.id+'\');},120)">'+r.title+'</div>';
      }).join('<br style="margin:2px 0">');
  }
  function dtTonightsDinner(){
    var inp=document.getElementById('dt-use-input');
    inp.style.display='none';_dtInputVisible=false;
    var res=document.getElementById('dt-result');
    var today=new Date();
    today.setHours(0,0,0,0);
    var todayKey=today.toISOString().slice(0,10);
    var plan=getPlanData();
    var dayPlan=plan[todayKey]||{};
    var dinnerSlot=dayPlan['Dinner']||[];
    var rid=dinnerSlot[0]||null;
    if(rid){
      var r=RECIPES.find(function(x){return x.id===rid;});
      if(r){
        res.innerHTML='<div style="font-size:11px;opacity:.55;margin-bottom:6px">Tonight\'s plan:</div>'+
          '<div class="dt-recipe-chip" data-action="openRecipeFromDinner" data-id="'+r.id+'">'+r.title+' ↗</div>';
        return;
      }
    }
    dtRollDinner();
  }
  function dtRollDinner(){
    var res=document.getElementById('dt-result');
    var pool=RECIPES.filter(function(r){return r.category==='meals'||r.category==='soups';});
    if(!pool.length)return;
    var r=pool[Math.floor(Math.random()*pool.length)];
    res.innerHTML='<div style="font-size:11px;opacity:.55;margin-bottom:6px">How about…</div>'+
      '<div style="display:inline-flex;align-items:center;gap:6px">'+
      '<div class="dt-recipe-chip" onclick=\"switchTab(\'recipes\');setTimeout(function(){openRecipe(\''+r.id+'\');},120)">'+r.title+' ↗</div>'+
      '<span style="cursor:pointer;font-size:20px;touch-action:manipulation" data-action="dtRollDinner" title="Re-roll">&#x1F3B2;</span></div>';
  }




  function parseFractionStr(s){if(!s)return s;var F={'½':0.5,'⅓':0.333,'⅔':0.667,'¼':0.25,'¾':0.75,'⅛':0.125,'⅜':0.375,'⅝':0.625,'⅞':0.875};var r=s.replace(/(\d*)\s*([½⅓⅔¼¾⅛⅜⅝⅞])/g,function(_,w,f){return String((parseInt(w)||0)+(F[f]||0));});r=r.replace(/(\d+)\s*\/\s*(\d+)/g,function(_,n,d){return String(parseFloat(n)/parseFloat(d));});r=r.replace(/(\d+(?:\.\d+)?)\s*[–-]\s*(\d+(?:\.\d+)?)/,'$1');return r.trim();}
