  function getPrepCategory(r){try{if(!r)return 6;var c=r.category||'',t=(r.title||'').toLowerCase(),x=((r.prep||'')+' '+(r.cook||'')).toLowerCase();if(c==='breads')return 0;if(c==='ferments'||/broth|kvass|kefir|yogurt/.test(t))return 1;if(/weeks|days ferment|overnight|12.24|8.12|incubat/.test(x))return 1;if(c==='soups')return 2;if(c==='condiments')return 3;if(c==='breakfast')return 4;if(c==='snacks'||c==='desserts')return 5;return 6;}catch(e){return 6;}}
  function parseActiveMins(s){if(!s||typeof s!=='string')return 0;var p=s.split('+')[0],total=0,h=p.match(/(\d+(?:\.\d+)?)\s*hr/i),m=p.match(/(\d+)\s*min/i);if(h)total+=parseFloat(h[1])*60;if(m)total+=parseInt(m[1]);return total;}
  function isLongPassive(a,b){var c=((a||'')+' '+(b||'')).toLowerCase();return /overnight|ferment|weeks|days|12.{0,3}24|8.{0,3}12|incubat|slow cooker/.test(c)||parseActiveMins(b)>=240;}
  function getOvenTemp(steps){if(!steps||!Array.isArray(steps))return null;var sentences=steps.map(function(s){return(s&&s.text)||'';}).join('. ').split(/[.!?]/);for(var i=0;i<sentences.length;i++){var s=sentences[i].toLowerCase();if(!/preheat|bake at|roast at/.test(s))continue;var m=s.match(/([2-4][0-9]{2})/);if(!m)continue;var before=s.slice(Math.max(0,s.indexOf(m[1])-30),s.indexOf(m[1]));if(/internal|reaches|register|thermometer/.test(before))continue;return parseInt(m[1]);}return null;}
