  function buildPrepByCategory(prepItems){if(!prepItems||!Array.isArray(prepItems)||!prepItems.length)return '';var groups={};for(var i=0;i<prepItems.length;i++){var item=prepItems[i];if(!item||typeof item!=='object')continue;var r=null;if(item.recipeId&&typeof item.recipeId==='string'){for(var j=0;j<RECIPES.length;j++){if(RECIPES[j]&&RECIPES[j].id===item.recipeId){r=RECIPES[j];break;}}}var ci=6;try{ci=getPrepCategory(r);}catch(e){}if(typeof ci!=='number'||ci<0||ci>6)ci=6;if(!groups[ci])groups[ci]=[];groups[ci].push({item:item,idx:i});}var out='';var cats=Object.keys(groups).map(Number).sort(function(a,b){return a-b;});for(var k=0;k<cats.length;k++){var catI=cats[k];var info=(PREP_CAT_LABELS&&PREP_CAT_LABELS[catI])||{emoji:'🤝',label:'Other'};var ents=groups[catI]||[];var ihtml='';for(var e=0;e<ents.length;e++){try{var en=ents[e];if(!en)continue;var it=en.item;var ix=typeof en.idx==='number'?en.idx:e;if(!it||typeof it!=='object')continue;var nm=typeof it.name==='string'?it.name:'';var ck=it.checked===true;var rid=typeof it.recipeId==='string'?it.recipeId:'';var r2=null;if(rid){for(var j2=0;j2<RECIPES.length;j2++){if(RECIPES[j2]&&RECIPES[j2].id===rid){r2=RECIPES[j2];break;}}}var rTimes='';if(r2){var rp=(r2.prep||'').split('+')[0].trim();var rc=(r2.cook||'').split('/')[0].trim();if(rc==='—'||rc.toLowerCase()==='none'||rc==='')rc='';if(rp)rTimes+='<span class="prep-time-badge">⏱ '+rp+'</span>';if(rc)rTimes+='<span class="prep-time-badge cook">🔥 '+rc+'</span>';}var timesHtml=rTimes?'<span class="prc-times">'+rTimes+'</span>':'';var nh=rid?('<button class="prep-recipe-chip '+(ck?'checked':'')+'" data-rid="'+rid+'" onclick="openRecipeFromPlan(this.dataset.rid)"><span class="prc-name">'+nm+' <span class="wv-arrow">↗</span></span>'+timesHtml+'</button>'):('<span class="prep-item-name '+(ck?'checked':'')+'">' +nm+'</span>');var nv='';try{nv=typeof it.note==='string'?it.note.replace(/"/g,'&quot;'):''; }catch(ne){}var hn=typeof it.note==='string'&&it.note.trim().length>0;var nid='prep-note-wrap-'+ix;ihtml+='<div class="prep-item-wrap"><div class="prep-item"><div class="prep-check '+(ck?'checked':'')+'" onclick="togglePrep('+ix+')">'+(ck?'✓':'')+'</div><div class="prep-item-main">'+nh+(hn?'<div class="prep-item-note-preview">'+(it.note||'')+'</div>':'')+'</div><input class="prep-note-inline" id="'+nid+'" placeholder="Add a note…" value="'+nv+'" oninput="savePrepNote('+ix+', this.value)" style="display:'+(hn?'flex':'none')+'"><button class="prep-note-toggle" onclick="togglePrepNote('+ix+')" title="Add note">📝</button><button class="prep-item-remove" onclick="removePrep('+ix+')">✕</button></div></div>';}catch(itemErr){}}out+='<div class="prep-cat-group"><div class="prep-cat-label">'+info.emoji+' '+info.label+'</div>'+ihtml+'</div>';}return out;}
