  // ── Action dispatcher (replaces inline handlers) ────────────────────────────
  // HTML uses data-action + data-* args so markup stays clean and safe.
  function closestActionEl(target){
    return target && target.closest ? target.closest('[data-action]') : null;
  }
  function getAttr(el, name){
    try { return el && el.getAttribute ? el.getAttribute(name) : null; } catch(e){ return null; }
  }
  function asInt(v){
    var n = parseInt(v, 10);
    return isNaN(n) ? 0 : n;
  }

  document.addEventListener('click', function (event) {
    var el = closestActionEl(event.target);
    if (!el) return;
    var action = getAttr(el, 'data-action');
    if (!action) return;

    try {
      if (action === 'switchTab') return switchTab(getAttr(el, 'data-tab'));
      if (action === 'setCat') return setCat(getAttr(el, 'data-cat'));
      if (action === 'openRecipe') return openRecipe(getAttr(el, 'data-id'));
      if (action === 'openRecipeFromFavs') return openRecipeFromFavs(getAttr(el, 'data-id'));
      if (action === 'openRecipeFromPlan') return openRecipeFromPlan(getAttr(el, 'data-id'));
      if (action === 'toggleFav') { if (event && event.stopPropagation) event.stopPropagation(); return toggleFav(getAttr(el, 'data-id')); }
      if (action === 'deleteMyRecipe') return deleteMyRecipe(getAttr(el, 'data-id'));
      if (action === 'openPicker') return openPicker(getAttr(el, 'data-dk'), getAttr(el, 'data-slot'));
      if (action === 'selectDay') return selectDay(asInt(getAttr(el, 'data-day-index')));
      if (action === 'removeFromSlot') return removeFromSlot(getAttr(el,'data-dk'), getAttr(el,'data-slot'), asInt(getAttr(el,'data-ri')));
      if (action === 'addQuickText') return addQuickText(getAttr(el,'data-dk'), getAttr(el,'data-slot'), getAttr(el,'data-text'));
      if (action === 'addPrep') return addPrep();
      if (action === 'openPrepRecipePicker') return openPrepRecipePicker();
      if (action === 'addPrepRecipe') { addPrepRecipe(getAttr(el,'data-id')); if (getAttr(el,'data-close-picker')) closePicker(); return; }
      if (action === 'addToSlot') { addToSlot(getAttr(el,'data-dk'), getAttr(el,'data-slot'), getAttr(el,'data-id')); if (getAttr(el,'data-close-picker')) closePicker(); return; }
      if (action === 'pickerSelectRecipe') return pickerSelectRecipe(getAttr(el,'data-id'));
      if (action === 'toggleShopItem') return toggleShopItem(getAttr(el,'data-key'));
      if (action === 'removeShopItem') return removeShopItem(getAttr(el,'data-key'));
      if (action === 'openPickerForRecipe') return openPickerForRecipe(getAttr(el,'data-id'));
      if (action === 'printRecipe') return printRecipe(getAttr(el,'data-id'));
      if (action === 'setServingMult') return setServingMult(getAttr(el,'data-id'), asInt(getAttr(el,'data-mult')) || 1);
      if (action === 'startTimer') return startTimer(asInt(getAttr(el,'data-mins')), el);
      if (action === 'openLinked') return (getAttr(el,'data-linked-type')==='chapter') ? openChapter(getAttr(el,'data-linked-id')) : openRecipeFromPlan(getAttr(el,'data-linked-id'));
      if (action === 'dtRollDinner') return dtRollDinner();
      if (action === 'openRecipeFromDinner') { switchTab('recipes'); setTimeout(function(){ openRecipe(getAttr(el,'data-id')); },120); return; }
      if (action === 'dismissParent') { if (el && el.parentElement) el.parentElement.remove(); return; }
      if (action === 'hardReload') { window.location.reload(true); return; }
      if (action === 'saveCurrentAsPlan') return saveCurrentAsPlan();
      if (action === 'loadMyPlan') return loadMyPlan(getAttr(el,'data-id'));
      if (action === 'deleteMyPlan') return deleteMyPlan(getAttr(el,'data-id'));
      if (action === 'loadPreloadedPlan') return loadPreloadedPlan(getAttr(el,'data-id'));
      if (action === 'dtUseWhatIHave') return dtUseWhatIHave();
      if (action === 'dtTonightsDinner') return dtTonightsDinner();
      if (action === 'backupData') return backupData();
      if (action === 'openRestorePicker') {
        var inp = document.getElementById('restore-input');
        if (inp) inp.click();
        return;
      }
      if (action === 'openAddMyRecipe') return openAddMyRecipe();
      if (action === 'openRandomRecipe') return openRandomRecipe();
      if (action === 'closeRecipeDetail') return closeRecipeDetail();
      if (action === 'setPlanView') return setPlanView(getAttr(el, 'data-view'));
      if (action === 'openPlanPicker') return openPlanPicker();
      if (action === 'switchPlanView') return switchPlanView(getAttr(el, 'data-target'));
      if (action === 'exportMealPlan') return exportMealPlan();
      if (action === 'changeWeek') return changeWeek(asInt(getAttr(el, 'data-delta')));
      if (action === 'clearCheckedShop') return clearCheckedShop();
      if (action === 'addShopItem') return addShopItem();
      if (action === 'openChapter') return openChapter(getAttr(el, 'data-chapter'));
      if (action === 'closeChapterDetail') return closeChapterDetail();
      if (action === 'closePicker') return closePicker();
      if (action === 'openPhoneClock') return openPhoneClock();
      if (action === 'cancelTimer') return cancelTimer();
      if (action === 'closeAddMyRecipe') return closeAddMyRecipe();
      if (action === 'saveMyRecipe') return saveMyRecipe();
      if (action === 'closePlanPicker') return closePlanPicker();
      if (action === 'dismissBanner') return dismissBanner();
    } catch (err) {
      try { console.error('data-action failed:', action, err); } catch (_) {}
    }
  }, true);

  // Inputs / change handlers moved out of HTML.
  window.addEventListener('load', function () {
    try {
      var dt = document.getElementById('dt-use-input');
      if (dt) {
        dt.addEventListener('input', function(){ dtFilterIngredients(dt.value); });
        dt.addEventListener('keydown', function(e){
          if (e && e.key === 'Enter') dtFilterIngredients(dt.value);
        });
      }

      var restore = document.getElementById('restore-input');
      if (restore) {
        restore.addEventListener('change', function(){ restoreData(restore); });
      }

      var recipeSearch = document.getElementById('recipe-search');
      if (recipeSearch) {
        recipeSearch.addEventListener('input', function(){ filterRecipes(); });
        recipeSearch.addEventListener('focus', function(){ onRecipeSearchFocus(); });
      }

      var shopAdd = document.getElementById('shop-add-input');
      if (shopAdd) {
        shopAdd.addEventListener('keydown', function(e){
          if (e && e.key === 'Enter') addShopItem();
        });
      }

      var pickerSearch = document.getElementById('picker-search');
      if (pickerSearch) {
        pickerSearch.addEventListener('input', function(){ filterPicker(); });
        pickerSearch.addEventListener('focus', function(){ onPickerSearchFocus(); });
        pickerSearch.addEventListener('blur', function(){ onPickerSearchBlur(); });
      }

      // Recipe notes autosave (replaces inline onchange on detail textarea)
      document.addEventListener('input', function(ev){
        var t = ev && ev.target;
        if (!t || !t.getAttribute) return;
        var rid = t.getAttribute('data-recipe-note');
        if (!rid) return;
        saveRecipeNote(rid, t.value || '');
      }, true);

      // Slot text + notes autosave (replaces inline oninput/onchange in plan UI)
      document.addEventListener('input', function(ev){
        var t = ev && ev.target;
        if (!t || !t.getAttribute) return;
        var key = t.getAttribute('data-slot-text');
        if (!key) return;
        var parts = key.split('|');
        if (parts.length < 2) return;
        saveSlotText(parts[0], parts[1], t.value || '');
      }, true);
      document.addEventListener('change', function(ev){
        var t = ev && ev.target;
        if (!t || !t.getAttribute) return;
        var key = t.getAttribute('data-slot-note');
        if (!key) return;
        var parts = key.split('|');
        if (parts.length < 2) return;
        saveSlotNote(parts[0], parts[1], t.value || '');
      }, true);

      // Plan picker inputs (rename + save via keyboard)
      document.addEventListener('keydown', function(ev){
        var t = ev && ev.target;
        if (!t || !t.getAttribute) return;
        if (t.getAttribute('data-plan-save-input') && ev.key === 'Enter') {
          ev.preventDefault();
          saveCurrentAsPlan();
        }
        if (t.getAttribute('data-plan-rename') && ev.key === 'Enter') {
          ev.preventDefault();
          t.blur();
        }
      }, true);
      document.addEventListener('blur', function(ev){
        var t = ev && ev.target;
        if (!t || !t.getAttribute) return;
        var sid = t.getAttribute('data-plan-rename');
        if (!sid) return;
        renameMyPlan(sid, t.value || '');
      }, true);
    } catch (e) {}
  });
